const input = $input.first().json || {};
let rows = input.result || [];
if (typeof rows === 'string') { try { rows = JSON.parse(rows); } catch(e) { rows = []; } }
if (!Array.isArray(rows)) rows = [];

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

if (rows.length === 0) {
  // Нет новых выпадающих — молчаливое утро (не спамим)
  return [{json: {skip: true, count: 0}}];
}

const lines = rows.slice(0, 15).map((r, i) => {
  const contacts = [r.tg ? '\ud83d\udce9TG' : null, r.phone ? '\u260e\ufe0fPH' : null].filter(x=>x).join(' ');
  const email = r.email ? '<code>' + esc(r.email) + '</code>' : '(no email)';
  return (i+1) + '. ' + email + ' \u2014 <b>\u20ac' + r.ltv_eur + '</b> LTV, ' + r.orders + ' \u0437\u0430\u043a\u0430\u0437\u043e\u0432, <b>' + r.days_silent + '\u0434</b> \u0442\u0438\u0448\u0438\u043d\u044b, ' + esc(r.fav_brand || '-') + ' ' + contacts;
}).join('\n\n');

const totalLtv = rows.reduce((s,r) => s + Number(r.ltv_eur||0), 0);
const today = new Date().toISOString().slice(0,10);
const text = '\u26a0\ufe0f <b>Champion Churn Alert</b> \u2014 ' + today + '\n<i>\u041f\u043e\u0440\u043e\u0433: LTV\u2265\u20ac500, \u0442\u0438\u0448\u0438\u043d\u0430 10-12 \u0434\u043d\u0435\u0439 (\u0432\u044b\u0448\u0435 P75 Nutaku \u043d\u043e \u043d\u0438\u0436\u0435 At Risk)</i>\n\n\u041d\u0430\u0439\u0434\u0435\u043d\u043e <b>' + rows.length + '</b> \u0447\u0435\u043b\u043e\u0432\u0435\u043a, \u0441\u0443\u043c\u043c\u0430\u0440\u043d\u044b\u0439 LTV <b>\u20ac' + totalLtv + '</b>:\n\n' + lines + '\n\n\u2192 \u041c\u0430\u043a\u0441\u0438\u043c: \u043b\u0438\u0447\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0430\u043a\u0442 \u0441\u0435\u0433\u043e\u0434\u043d\u044f. 2 \u0434\u043d\u044f \u0438 \u044d\u0442\u0438 \u044e\u0437\u0435\u0440\u044b \u0443\u0439\u0434\u0443\u0442 \u0432 At Risk.';

return [{json: {text, count: rows.length, rows}}];
